class Solution(object):
    def canEat(self, candiesCount, queries):
        prefix = [0]
        for count in candiesCount:
            prefix.append(prefix[-1] + count)
        result = []
        for favorite_type, favorite_day, daily_cap in queries:
            min_day = (prefix[favorite_type] + 1 + daily_cap - 1) // daily_cap
            max_day = prefix[favorite_type + 1]
            result.append(favorite_day >= min_day and favorite_day < max_day)
        return result
